import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"4、皇帝【IV】","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/4、皇帝【IV】.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/4、皇帝【IV】.md"}'),d={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/4、皇帝【IV】.md"};function p(_,a,i,l,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_4、皇帝【iv】",tabindex:"-1"},[s("4、皇帝【IV】 "),e("a",{class:"header-anchor",href:"#_4、皇帝【iv】","aria-label":'Permalink to "4、皇帝【IV】"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="皇帝" tabindex="-1">皇帝 <a class="header-anchor" href="#皇帝" aria-label="Permalink to &quot;皇帝&quot;">​</a></h1><p>皇帝</p><p>B+2400<br> 替身外貌：<br> 左轮手枪外型的替身，主体银色，外表像是左轮手枪和自动手枪的结合体。</p><p>替身数据：<br> 破坏力B<br> 速度B（闪避防御）<br> 射程B<br> 持续力C<br> 精密动作性E<br> 成长性E</p><p>替身对应主属性：敏捷</p><p>替身能力：<br> 转向子弹：皇帝作为手枪型替身能够发射属于替身一部分的子弹，并且控制子弹的转向，转向的机动性与飞行的良好机动性相当，同时子弹具有替身的应有的所有特性，子弹会在射中目标或移动过等于射程范围的距离后消失。<br> 替身使者通过皇帝使用的以标准动作进行的射击时，可以对具有感知线与效果线的目标进行非线性的攻击。并且由于其转向效果，在第一次面对其转向效果会陷入B级措手不及的状态。<br> （例：皇帝与目标A处于一个L型拐角的两侧，且皇帝具有对目标A的感知线，而从皇帝到目标A的L型路程中没有阻挡射击的全掩蔽障碍物，皇帝就可以让子弹从皇帝所在的拐角处射击至目标A所在的位置。）</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const V=r(d,[["render",p]]);export{f as __pageData,V as default};
